import java.util.Scanner;

public class Calculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        String input;

        System.out.println("Welcome to the Java Calculator!");
        System.out.println("Type 'help' for a list of commands.");

        while (true) {
            System.out.print(">> ");
            input = scanner.nextLine().trim();

            if (input.equalsIgnoreCase("quit")) {
                System.out.println("Goodbye!");
                break;
            } else if (input.equalsIgnoreCase("help")) {
                printHelp();
            } else {
                try {
                    processInput(input);
                } catch (Exception e) {
                    System.err.println("Error: " + e.getMessage());
                }
            }
        }

        scanner.close();
    }

    private static void printHelp() {
        System.out.println("Available commands:");
        System.out.println("  <expression>   Evaluate a mathematical expression");
        System.out.println("  quit           Exit the calculator");
        System.out.println("  help           Show this help menu");
    }

    private static void processInput(String input) throws Exception {
        String[] parts = input.split("\\s+");

        if (parts.length < 3) {
            throw new IllegalArgumentException("Invalid expression format. Use: operand1 operator operand2");
        }

        String op1Str = parts[0];
        String operator = parts[1];
        String op2Str = parts[2];

        try {
            double op1 = Double.parseDouble(op1Str);
            double op2 = Double.parseDouble(op2Str);

            double result;
            switch (operator) {
                case "+":
                    result = op1 + op2;
                    break;
                case "-":
                    result = op1 - op2;
                    break;
                case "*":
                    result = op1 * op2;
                    break;
                case "/":
                    if (op2 == 0) {
                        throw new ArithmeticException("Division by zero is not allowed.");
                    }
                    result = op1 / op2;
                    break;
                default:
                    throw new IllegalArgumentException("Unsupported operator: " + operator);
            }

            System.out.println("Result: " + result);
        } catch (NumberFormatException e) {
            throw new IllegalArgumentException("Invalid number format. Please provide valid numeric operands.");
        }
    }
}

import java.util.Scanner;

public class Calculator {
    private static final Scanner SCANNER = new Scanner(System.in);

    public static void main(String[] args) {
        printHelp();
        while (true) {
            System.out.print("> ");
            String line = SCANNER.nextLine().trim();
            if (line.isEmpty()) {
                continue;
            }
            String[] parts = line.split("\\s+", 3);
            String command = parts[0].toLowerCase();

            switch (command) {
                case "quit":
                    System.out.println("Goodbye!");
                    return;
                case "help":
                    printHelp();
                    break;
                case "+":
                case "-":
                case "*":
                case "/":
                    if (parts.length != 3) {
                        System.out.println("Error: expected format: <num> <op> <num>");
                        break;
                    }
                    double left, right;
                    try {
                        left = Double.parseDouble(parts[1]);
                        right = Double.parseDouble(parts[2]);
                    } catch (NumberFormatException e) {
                        System.out.println("Error: operands must be valid numbers.");
                        break;
                    }
                    double result;
                    switch (command) {
                        case "+":
                            result = left + right;
                            break;
                        case "-":
                            result = left - right;
                            break;
                        case "*":
                            result = left * right;
                            break;
                        case "/":
                            if (right == 0) {
                                System.out.println("Error: division by zero is not allowed.");
                                continue;
                            }
                            result = left / right;
                            break;
                        default:
                            System.out.println("Unsupported operator.");
                            continue;
                    }
                    System.out.println("= " + result);
                    break;
                default:
                    System.out.println("Unknown command. Type 'help' for available commands.");
            }
        }
    }

    private static void printHelp() {
        System.out.println("=== Simple Calculator ===");
        System.out.println("Supported commands:");
        System.out.println("  <num> <op> <num>   Perform arithmetic ( + - * / )");
        System.out.println("  quit               Exit the program");
        System.out.println("  help               Show this help message");
        System.out.println("Operators: +, -, *, /");
        System.out.println("Division by zero will produce an error message.");
        System.out.println("==========================");
    }
}

import java.util.Scanner;
import java.util.regex.Pattern;

public class Calculator {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("=== Java Calculator ===");
        System.out.println("Type 'help' for commands.");
        System.out.println("Type 'quit' to exit.");

        while (true) {
            System.out.print("> ");
            String input = scanner.nextLine();

            String trimmedInput = input.trim();

            // Check for quit command
            if (trimmedInput.equalsIgnoreCase("quit")) {
                System.out.println("Goodbye!");
                break;
            }

            // Check for help command
            if (trimmedInput.equalsIgnoreCase("help")) {
                printHelp();
                continue;
            }

            // Check for empty input
            if (trimmedInput.isEmpty()) {
                System.out.println("Error: Input cannot be empty.");
                continue;
            }

            // Validate input format (basic regex to ensure it looks like math)
            // Allow digits, operators (+, -, *, /), parentheses, and spaces.
            if (!trimmedInput.matches("[0-9+\\-*/().\\s]+")) {
                System.out.println("Error: Invalid characters in expression.");
                continue;
            }

            try {
                // Using eval to handle complex expressions and operator precedence
                double result = (double) eval(trimmedInput);
                System.out.println("Result: " + result);
            } catch (ArithmeticException e) {
                System.out.println("Error: Division by zero.");
            } catch (NumberFormatException e) {
                System.out.println("Error: Invalid number format.");
            } catch (ClassCastException e) {
                System.out.println("Error: Invalid expression type.");
            } catch (Exception e) {
                System.out.println("Error: " + e.getMessage());
            }
        }
        scanner.close();
    }

    private static void printHelp() {
        System.out.println("Commands:");
        System.out.println("  +, -, *, /  : Arithmetic operations");
        System.out.println("  ( )        : Parentheses for grouping");
        System.out.println("  help       : Show this help");
        System.out.println("  quit       : Exit the calculator");
    }
}
